package yrpc.test.helloworld;

import "google/api/annotations.proto";

// 外部引用当前资源的 import 代码写法取决于 go_package 的设置，同时也需要保持生成的 pb 文件位于 go_package 指定的文件夹下
option go_package="github.com/HwanYan/yrpc-proto/helloworld";

// 定义服务接口
service Greeter {
 rpc SayHello (HelloRequest) returns (HelloResponse) {
 option (google.api.http) = {
 post: "/v1/hello"
 body: "*"
 };
 }
}","apply_mode":"apply_only"}},"timestamp":1777031983,"type":"TOOL_CALL_ARGS"}

{"rawEvent":{"message_id":"019dbf5af23473a0b3de956157969b42","conversation_id":"019dbf34cb657973a39e3274a1866f16","tool_call_id":"call_ab9576f6-17bc-4047-a879-ae3010878d89","document":{"file_path":"/Users/hwanyan/GolandProjects/mildlab-proto/example/main.go","sub_content":"main.go","sub_content_event":"open_editor","sub_content_event_value":"/Users/hwanyan/GolandProjects/mildlab-proto/example/main.go","sub_content_tip":"/Users/hwanyan/GolandProjects/mildlab-proto/example/main.go","apply_content":"package main

import (
	"context"
	"fmt"
	"log"
	"net/http"

	"github.com/HwanYan/yrpc-proto/helloworld"
	"github.com/grpc-ecosystem/grpc-gateway/v2/runtime"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
)

// GreeterServer 实现 gRPC 服务端
type GreeterServer struct {
	helloworld.UnimplementedGreeterServer
}

// SayHello 实现 gRPC 方法
func (s *GreeterServer) SayHello(ctx context.Context, req *helloworld.HelloRequest) (*helloworld.HelloResponse, error) {
	return &helloworld.HelloResponse{
		Msg: fmt.Sprintf("Hello, %s!", req.Msg),
	}, nil
}

// startGRPCServer 启动 gRPC 服务端
func startGRPCServer() {
	lis, err := net.Listen("tcp", ":50051")
	if err != nil {
		log.Fatalf("failed to listen: %v", err)
	}

	s := grpc.NewServer()
	helloworld.RegisterGreeterServer(s, &GreeterServer{})

	log.Printf("gRPC server listening at %v", lis.Addr())
	if err := s.Serve(lis); err != nil {
		log.Fatalf("failed to serve: %v", err)
	}
}

// startHTTPServer 启动 HTTP 网关服务器
func startHTTPServer() {
	ctx := context.Background()
	ctx, cancel := context.WithCancel(ctx)
	defer cancel()

	// 创建 gRPC 网关 mux
	mux := runtime.NewServeMux()

	// 注册 gRPC 网关处理器
	opts := []grpc.DialOption{grpc.WithTransportCredentials(insecure.NewCredentials())}
	err := helloworld.RegisterGreeterHandlerFromEndpoint(ctx, mux, "localhost:50051", opts)
	if err != nil {
		log.Fatalf("failed to register gateway: %v", err)
	}

	log.Printf("HTTP gateway server listening at :8080")
	if err := http.ListenAndServe(":8080", mux); err != nil {
		log.Fatalf("failed to serve HTTP: %v", err)
	}
}

// gRPCClientExample gRPC 客户端示例
func gRPCClientExample() {
	conn, err := grpc.Dial("localhost:50051", grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		log.Fatalf("did not connect: %v", err)
	}
	defer conn.Close()

	client := helloworld.NewGreeterClient(conn)

	resp, err := client.SayHello(context.Background(), &helloworld.HelloRequest{Msg: "World"})
	if err != nil {
		log.Fatalf("could not greet: %v", err)
	}

	fmt.Printf("gRPC Response: %s\n", resp.Msg)
}

// HTTPClientExample HTTP 客户端示例
func HTTPClientExample() {
	resp, err := http.Post("http://localhost:8080/v1/hello", "application/json", 
		strings.NewReader(`{"msg": "World"}`))
	if err != nil {
		log.Fatalf("HTTP request failed: %v", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		log.Fatalf("failed to read response: %v", err)
	}

	fmt.Printf("HTTP Response: %s\n", string(body))
}

func main() {
	// 在单独的 goroutine 中启动 gRPC 服务器
	go startGRPCServer()

	// 在单独的 goroutine 中启动 HTTP 网关
	go startHTTPServer()

	// 等待服务器启动
	time.Sleep(2 * time.Second)

	// 测试 gRPC 客户端
	fmt.Println("=== gRPC Client Test ===")
	gRPCClientExample()

	// 测试 HTTP 客户端
	fmt.Println("=== HTTP Client Test ===")
	HTTPClientExample()

	// 保持程序运行
	select {}
}","instruction":"创建一个完整的示例，展示如何使用生成的 RPC 代码","apply_mode":"apply_only"}},"timestamp":1777032152,"type":"TOOL_CALL_ARGS"}

